demos.desktop:
const PERIOD_OPTIONS = [
{ key: 'week', content: 'Неделя' },
{ key: 'month', content: 'Месяц' },
{ key: 'year', content: 'Год' },
];

const ACCOUNT_OPTIONS = [
{ key: 'acc1', content: 'Счёт 1' },
{ key: 'acc2', content: 'Счёт 2' },
];

const DYNAMIC_META = {
added_expenses: 'Добавленные расходы',
to_client: 'Клиенту банка',
between_accounts: 'Между счетами',
templates: 'Шаблоны',
autopay: 'Автоплатежи',
};

const EMPTY = () => ({
replenishment: false,
writeoff: false,
dynamicKeys: [],
period: null,
accounts: [],
});

const countActive = ({ accounts, dynamicKeys, period, replenishment, writeoff }) => {
let n = 0;
if (replenishment) n += 1;
if (writeoff) n += 1;
n += dynamicKeys.length;
if (period) n += 1;
n += accounts.length;

return n;
};

const DESKTOP_TAG_SIZE = 40;
const OPTIONS_LIST_ROW_SIZE = 40;

render(() => {
const [panelOpen, setPanelOpen] = React.useState(false);
const [countIndicator, setCountIndicator] = React.useState(false);
const [applied, setApplied] = React.useState(EMPTY);
const [draft, setDraft] = React.useState(EMPTY);

const openOrTogglePanel = () => {
if (panelOpen) {
setPanelOpen(false);
} else {
setDraft({ ...applied });
setPanelOpen(true);
}
};

const activeCount = countActive(applied);

const toggleDraftDynamic = (id) => {
setDraft((prev) => {
const has = prev.dynamicKeys.includes(id);

if (has) {
return { ...prev, dynamicKeys: prev.dynamicKeys.filter((k) => k !== id) };
}

return { ...prev, dynamicKeys: [...prev.dynamicKeys, id] };
});
};

const toggleAppliedDynamic = (id) => {
setApplied((prev) => ({
...prev,
dynamicKeys: prev.dynamicKeys.filter((k) => k !== id),
}));
};

const [periodOpen, setPeriodOpen] = React.useState(false);
const [accountsOpen, setAccountsOpen] = React.useState(false);
const [periodAnchorEl, setPeriodAnchorEl] = React.useState(null);
const [accountsAnchorEl, setAccountsAnchorEl] = React.useState(null);

const appliedPeriodOption = React.useMemo(
() => PERIOD_OPTIONS.find((o) => o.key === applied.period),
[applied.period],
);

const accountsSelectedOpts = React.useMemo(
() => ACCOUNT_OPTIONS.filter((o) => applied.accounts.includes(o.key)),
[applied.accounts],
);

const filterSectionTitleStyle = { fontSize: 22, lineHeight: '28px' };

return (
<Container>
<style>
{`
.tag-filter-popover-panel {
width: 280px;
border-radius: 0;
border: none;
background: transparent;
box-shadow: none;
}
.tag-filter-row-options {
border-radius: 16px;
border: 1px solid var(--neutral-300, #E7E8EB);
background: var(--modal-bg-primary, #FFF);
box-shadow:
0 20px 24px 0 rgba(0, 0, 0, 0.08),
0 12px 16px 0 rgba(0, 0, 0, 0.04),
0 4px 8px 0 rgba(0, 0, 0, 0.04),
0 0 1px 0 rgba(0, 0, 0, 0.04);
overflow: hidden;
}
.tag-filter-panel-footer {
padding: 24px 32px 32px !important;
}
.tag-filter-side-panel-scroll {
flex: 1 1 auto;
min-height: 0;
overflow-y: auto;
box-sizing: border-box;
padding: var(--gap-0)  var(--gap-40);
}
.tag-filter-side-panel-scroll:last-child {
padding-bottom: var(--gap-32) !important;
}
.tag-filter-side-panel-header {
padding: 20px 28px 0 28px !important;
}
`}
</style>
<div
style={{
display: 'flex',
flexWrap: 'wrap',
gap: 8,
alignItems: 'center',
}}
>
<TagDesktop
Component={IndicatorTag}
leftAddons={<SlidersSIcon height={16} width={16} />}
size={DESKTOP_TAG_SIZE}
view='filled'
shape='rectangular'
checked={false}
indicatorProps={
activeCount > 0
? countIndicator
? { mode: 'count', value: activeCount }
: { mode: 'dot' }
: undefined
}
onClick={openOrTogglePanel}
/>
{applied.dynamicKeys.map((id) => (
<TagDesktop
key={id}
size={DESKTOP_TAG_SIZE}
view='filled'
shape='rectangular'
checked={true}
onClick={() => toggleAppliedDynamic(id)}
>
{DYNAMIC_META[id]}
</TagDesktop>
))}
<TagDesktop
size={DESKTOP_TAG_SIZE}
view='filled'
shape='rectangular'
checked={applied.replenishment}
onClick={() => setApplied((p) => ({ ...p, replenishment: !p.replenishment }))}
>
Пополнения
</TagDesktop>
<TagDesktop
size={DESKTOP_TAG_SIZE}
view='filled'
shape='rectangular'
checked={applied.writeoff}
onClick={() => setApplied((p) => ({ ...p, writeoff: !p.writeoff }))}
>
Списания
</TagDesktop>
<div>
<FilterTagDesktop
ref={setPeriodAnchorEl}
client='desktop'
size={DESKTOP_TAG_SIZE}
view='filled'
shape='rectangular'
showClear={false}
checked={Boolean(applied.period)}
open={periodOpen}
onClick={() => {
setAccountsOpen(false);
setPeriodOpen((v) => !v);
}}
>
{appliedPeriodOption ? (
<>
Период:
<span style={{ fontWeight: 700 }}>
{appliedPeriodOption.content}
</span>
</>
) : (
'Период'
)}
</FilterTagDesktop>
<Popover
anchorElement={periodAnchorEl}
open={periodOpen}
position='bottom-start'
offset={[0, 4]}
preventFlip={true}
popperClassName='tag-filter-popover-panel'
>
<OptionsList
Option={Option}
className='tag-filter-row-options'
client='desktop'
nativeScrollbar={true}
size={OPTIONS_LIST_ROW_SIZE}
options={PERIOD_OPTIONS}
open={periodOpen}
selectedItems={PERIOD_OPTIONS.filter((item) => item.key === applied.period)}
getOptionProps={(option, index) => ({
option,
index,
mobile: false,
multiple: false,
selected: applied.period === option.key,
innerProps: {
id: `tag-doc-desktop-period-${option.key}`,
role: 'option',
onMouseDown: (e) => e.preventDefault(),
onClick: () => {
setApplied((p) => ({
...p,
period: p.period === option.key ? null : option.key,
}));
setPeriodOpen(false);
},
},
})}
/>
</Popover>
</div>
<div>
<FilterTagDesktop
ref={setAccountsAnchorEl}
client='desktop'
size={DESKTOP_TAG_SIZE}
view='filled'
shape='rectangular'
showClear={false}
checked={applied.accounts.length > 0}
open={accountsOpen}
onClick={() => {
setPeriodOpen(false);
setAccountsOpen((v) => !v);
}}
>
{accountsSelectedOpts.length === 0 ? (
'Счета'
) : accountsSelectedOpts.length === 1 ? (
<>
Счета:
<span style={{ fontWeight: 700 }}>
{accountsSelectedOpts[0].content}
</span>
</>
) : (
<>
Счета:
<span style={{ fontWeight: 700 }}>
Выбрано {accountsSelectedOpts.length}
</span>
</>
)}
</FilterTagDesktop>
<Popover
anchorElement={accountsAnchorEl}
open={accountsOpen}
position='bottom-start'
offset={[0, 4]}
preventFlip={true}
popperClassName='tag-filter-popover-panel'
>
<OptionsList
Option={Option}
className='tag-filter-row-options'
client='desktop'
nativeScrollbar={true}
size={OPTIONS_LIST_ROW_SIZE}
options={ACCOUNT_OPTIONS}
open={accountsOpen}
multiple={true}
selectedItems={ACCOUNT_OPTIONS.filter((item) =>
applied.accounts.includes(item.key),
)}
getOptionProps={(option, index) => ({
option,
index,
mobile: false,
multiple: true,
selected: applied.accounts.includes(option.key),
innerProps: {
id: `tag-doc-desktop-accounts-${option.key}`,
role: 'option',
onMouseDown: (e) => e.preventDefault(),
onClick: () => {
setApplied((p) => {
const selected = p.accounts.includes(option.key);

return {
...p,
accounts: selected
? p.accounts.filter((k) => k !== option.key)
: [...p.accounts, option.key],
};
});
},
},
})}
/>
</Popover>
</div>
</div>

<Gap size={20} />

<div style={{ width: '100%', alignSelf: 'stretch' }}>
<Divider />
</div>

<Gap size={20} />

<Switch
checked={countIndicator}
label='Индикатор с цифрой'
onChange={() => setCountIndicator((v) => !v)}
