const PERIOD_OPTIONS = [
{ key: 'week', content: 'Неделя' },
{ key: 'month', content: 'Месяц' },
{ key: 'year', content: 'Год' },
];

const ACCOUNT_OPTIONS = [
{ key: 'acc1', content: 'Счёт 1' },
{ key: 'acc2', content: 'Счёт 2' },
];

const DYNAMIC_META = {
added_expenses: 'Добавленные расходы',
to_client: 'Клиенту банка',
between_accounts: 'Между счетами',
templates: 'Шаблоны',
autopay: 'Автоплатежи',
};

const EMPTY = () => ({
replenishment: false,
writeoff: false,
dynamicKeys: [],
period: null,
accounts: [],
});

const toggleInArray = (arr, value) =>
arr.includes(value) ? arr.filter((item) => item !== value) : [...arr, value];

const countActive = (filters) =>
[
filters.replenishment,
filters.writeoff,
filters.period,
...filters.dynamicKeys,
...filters.accounts,
].filter(Boolean).length;

const MOBILE_ROW_TAG_SIZE = 32;
const OPTIONS_LIST_ROW_SIZE = 40;

const DYNAMIC_GROUPS = [
{
title: 'Движение средств',
items: [
{ key: 'replenishment', label: 'Пополнение', type: 'boolean' },
{ key: 'writeoff', label: 'Списание', type: 'boolean' },
{ key: 'added_expenses', label: DYNAMIC_META.added_expenses, type: 'dynamic' },
],
},
{
title: 'Переводы',
items: [
{ key: 'to_client', label: DYNAMIC_META.to_client, type: 'dynamic' },
{ key: 'between_accounts', label: DYNAMIC_META.between_accounts, type: 'dynamic' },
],
},
{
title: 'Шаблоны и автоплатежи',
items: [
{ key: 'templates', label: DYNAMIC_META.templates, type: 'dynamic' },
{ key: 'autopay', label: DYNAMIC_META.autopay, type: 'dynamic' },
],
},
];

const FilterTagItem = ({ checked, onClick, size = MOBILE_ROW_TAG_SIZE, children }) => (
<TagMobile size={size} view='filled' shape='rectangular' checked={checked} onClick={onClick}>
{children}
</TagMobile>
);

const CheckboxItem = ({ selected, disabled, position }) => (
<span
style={{
display: 'flex',
alignItems: 'center',
flexShrink: 0,
...(position === 'before'
? { marginRight: 'var(--gap-12)' }
: { marginLeft: 'var(--gap-12)' }),
}}
>
<Checkbox
hiddenInput={true}
checked={Boolean(selected)}
disabled={disabled}
size={24}
position={position}
/>
</span>
);

render(() => {
const [panelOpen, setPanelOpen] = React.useState(false);
const [countIndicator, setCountIndicator] = React.useState(false);
const [applied, setApplied] = React.useState(EMPTY);
const [draft, setDraft] = React.useState(EMPTY);
const [filterSheet, setFilterSheet] = React.useState(null);
const [accountsSheetDraft, setAccountsSheetDraft] = React.useState([]);
const prevFilterSheetRef = React.useRef(null);

const updateApplied = (patch) => setApplied((prev) => ({ ...prev, ...patch }));
const updateDraft = (patch) => setDraft((prev) => ({ ...prev, ...patch }));

const closeFilterSheet = () => setFilterSheet(null);

const toggleFilterSheet = (name) => {
setFilterSheet((prev) => (prev === name ? null : name));
};

React.useEffect(() => {
if (filterSheet) {
setPanelOpen(false);
}
}, [filterSheet]);

React.useEffect(() => {
if (filterSheet === 'accounts' && prevFilterSheetRef.current !== 'accounts') {
setAccountsSheetDraft([...applied.accounts]);
}
prevFilterSheetRef.current = filterSheet;
}, [filterSheet, applied.accounts]);

const openOrTogglePanel = () => {
setFilterSheet(null);
setPanelOpen((isOpen) => {
if (isOpen) return false;

setDraft({ ...applied });
return true;
});
};

const closePanel = () => {
setPanelOpen(false);
setFilterSheet(null);
};
const activeCount = countActive(applied);

const toggleDraftDynamic = (key) =>
updateDraft({
dynamicKeys: toggleInArray(draft.dynamicKeys, key),
});

const appliedPeriodOption = React.useMemo(
() => PERIOD_OPTIONS.find((o) => o.key === applied.period),
[applied.period],
);

const accountsSelectedOpts = React.useMemo(
() => ACCOUNT_OPTIONS.filter((o) => applied.accounts.includes(o.key)),
[applied.accounts],
);

const mobileFilterTagsScrollRowStyle = {
display: 'flex',
flexDirection: 'row',
flexWrap: 'nowrap',
gap: 8,
alignItems: 'center',
overflowX: 'auto',
overflowY: 'hidden',
WebkitOverflowScrolling: 'touch',
touchAction: 'pan-x',
paddingTop: 10,
paddingBottom: 4,
boxSizing: 'border-box',
width: 'max-content',
maxWidth: '100%',
minWidth: 0,
scrollbarWidth: 'none',
msOverflowStyle: 'none',
};

const mobileFilterSheetTagsRowStyle = {
display: 'flex',
flexDirection: 'row',
flexWrap: 'wrap',
gap: 8,
alignItems: 'center',
};

return (
<Container>
<style>
{`
.tag-doc-mobile-filter-tags-scroll::-webkit-scrollbar {
display: none;
width: 0;
height: 0;
}
.tag-filter-row-options {
border-radius: 16px;
overflow: hidden;
}
.tag-doc-mobile-bottom-sheet-content {
padding-left: 4px;
padding-right: 2px;
box-sizing: border-box;
}
.tag-doc-mobile-sheet-options [class*='textContent'] {
padding-top: var(--gap-16);
padding-bottom: var(--gap-16);
}
`}
</style>
<div
style={{
display: 'inline-grid',
gridTemplateColumns: 'minmax(0, max-content)',
maxWidth: '100%',
}}
>
<div
className='tag-doc-mobile-filter-tags-scroll'
style={mobileFilterTagsScrollRowStyle}
>
<div style={{ display: 'flex' }}>
<TagMobile
Component={IndicatorTag}
leftAddons={<SlidersSIcon height={16} width={16} />}
size={MOBILE_ROW_TAG_SIZE}
view='filled'
shape='rectangular'
checked={false}
indicatorProps={
activeCount > 0
? countIndicator
? { mode: 'count', value: activeCount }
: { mode: 'dot' }
: undefined
}
onClick={openOrTogglePanel}
/>
</div>

{applied.dynamicKeys.map((id) => (
<div key={id}>
<FilterTagItem
checked={true}
onClick={() =>
updateApplied({
dynamicKeys: applied.dynamicKeys.filter(
(key) => key !== id,
),
})
}
>
{DYNAMIC_META[id]}
</FilterTagItem>
</div>
))}

<div>
<FilterTagItem
checked={applied.replenishment}
onClick={() => updateApplied({ replenishment: !applied.replenishment })}
>
Пополнения
</FilterTagItem>
</div>
<div>
<FilterTagItem
checked={applied.writeoff}
onClick={() => updateApplied({ writeoff: !applied.writeoff })}
>
Списания
</FilterTagItem>
</div>

<div>
<FilterTagMobile
client='mobile'
size={MOBILE_ROW_TAG_SIZE}
view='filled'
shape='rectangular'
showClear={false}
checked={Boolean(applied.period)}
open={filterSheet === 'period'}
onClick={() => toggleFilterSheet('period')}
>
{appliedPeriodOption ? (
<>
Период:
<span style={{ fontWeight: 700 }}>
{appliedPeriodOption.content}
</span>
</>
) : (
'Период'
)}
</FilterTagMobile>
</div>
<div>
<FilterTagMobile
client='mobile'
size={MOBILE_ROW_TAG_SIZE}
view='filled'
shape='rectangular'
showClear={false}
checked={applied.accounts.length > 0}
open={filterSheet === 'accounts'}
onClick={() => toggleFilterSheet('accounts')}
>
{accountsSelectedOpts.length === 0 ? (
'Счета'
) : accountsSelectedOpts.length === 1 ? (
<>
Счета:
<span style={{ fontWeight: 700 }}>
{accountsSelectedOpts[0].content}
</span>
</>
) : (
<>
Счета:
<span style={{ fontWeight: 700 }}>
Выбрано {accountsSelectedOpts.length}
</span>
</>
)}
</FilterTagMobile>
</div>
</div>

<Gap size={20} />

<div style={{ width: '100%', minWidth: 0 }}>
<Divider />
</div>
</div>

<Gap size={20} />

<Switch
checked={countIndicator}
label='Индикатор с цифрой'
onChange={() => setCountIndicator((v) => !v)}
/>

<BottomSheet
open={filterSheet === 'period'}
onClose={closeFilterSheet}
title='Период'
hasCloser={true}
stickyFooter={false}
initialHeight='default'
contentClassName='tag-doc-mobile-bottom-sheet-content'
>
<OptionsList
Option={Option}
className='tag-filter-row-options tag-doc-mobile-sheet-options'
client='mobile'
nativeScrollbar={true}
size={OPTIONS_LIST_ROW_SIZE}
options={PERIOD_OPTIONS}
open={filterSheet === 'period'}
selectedItems={PERIOD_OPTIONS.filter((item) => item.key === applied.period)}
getOptionProps={(option, index) => ({
option,
index,
mobile: true,
multiple: false,
selected: applied.period === option.key,
innerProps: {
id: `tag-doc-mobile-period-sheet-${option.key}`,
role: 'option',
onMouseDown: (e) => e.preventDefault(),
onClick: () => {
updateApplied({
period: applied.period === option.key ? null : option.key,
});
closeFilterSheet();
},
},
})}
/>
</BottomSheet>

<BottomSheet
open={filterSheet === 'accounts'}
onClose={closeFilterSheet}
title='Счета'
hasCloser={true}
stickyFooter={true}
initialHeight='default'
contentClassName='tag-doc-mobile-bottom-sheet-content'
actionButton={
<div
style={{
display: 'flex',
flexDirection: 'row',
gap: 16,
width: '100%',
boxSizing: 'border-box',
}}
>
<ButtonMobile
view='secondary'
size={48}
type='button'
block={true}
style={{ flex: 1 }}
onClick={() => setAccountsSheetDraft([])}
>
Сбросить
</ButtonMobile>
<ButtonMobile
view='primary'
size={48}
type='button'
block={true}
style={{ flex: 1 }}
onClick={() => {
updateApplied({ accounts: accountsSheetDraft });
closeFilterSheet();
}}
>
Применить
</ButtonMobile>
</div>
}
>
<OptionsList
Option={Option}
className='tag-filter-row-options tag-doc-mobile-sheet-options'
client='mobile'
nativeScrollbar={true}
size={OPTIONS_LIST_ROW_SIZE}
options={ACCOUNT_OPTIONS}
open={filterSheet === 'accounts'}
multiple={true}
selectedItems={ACCOUNT_OPTIONS.filter((item) =>
accountsSheetDraft.includes(item.key),
)}
getOptionProps={(option, index) => ({
option,
index,
mobile: true,
multiple: true,
Checkmark: CheckboxItem,
selected: accountsSheetDraft.includes(option.key),
innerProps: {
