boxSizing: 'border-box',
}}
>
<ButtonMobile
view='secondary'
size={48}
type='button'
block={true}
style={{ flex: 1 }}
onClick={() => setDraft(EMPTY)}
>
Сбросить
</ButtonMobile>
<ButtonMobile
view='primary'
size={48}
type='button'
block={true}
style={{ flex: 1 }}
onClick={() => {
setApplied({ ...draft });
closePanel();
}}
>
Применить
