<div key={item.key}>
<FilterTagItem
checked={checked}
onClick={() => {
if (item.type === 'boolean') {
updateDraft({
[item.key]: !draft[item.key],
});
return;
}

toggleDraftDynamic(item.key);
}}
>
{item.label}
</FilterTagItem>
